(window.webpackJsonp=window.webpackJsonp||[]).push([[325],{620:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">capacity</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> DinnerPlates = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">capacity</span>) </span>{\\n  <span class=\\"hljs-keyword\\">this</span>.stackArr=[]\\n  <span class=\\"hljs-keyword\\">this</span>.capacity=capacity\\n  <span class=\\"hljs-keyword\\">this</span>.nextInsertPos=<span class=\\"hljs-number\\">0</span>\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * @param {number} val\\n * @return {void}\\n */</span>\\nDinnerPlates.prototype.push = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">val</span>) </span>{\\n\\n  <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-keyword\\">this</span>.stackArr[<span class=\\"hljs-keyword\\">this</span>.nextInsertPos]==<span class=\\"hljs-literal\\">null</span>){\\n    <span class=\\"hljs-keyword\\">this</span>.stackArr[<span class=\\"hljs-keyword\\">this</span>.nextInsertPos]=[]\\n  }\\n  <span class=\\"hljs-keyword\\">this</span>.stackArr[<span class=\\"hljs-keyword\\">this</span>.nextInsertPos].push(val)\\n  <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-keyword\\">this</span>.stackArr[<span class=\\"hljs-keyword\\">this</span>.nextInsertPos].length===<span class=\\"hljs-keyword\\">this</span>.capacity){\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-keyword\\">this</span>.nextInsertPos+<span class=\\"hljs-number\\">1</span>;i&lt;<span class=\\"hljs-literal\\">Infinity</span>;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-keyword\\">this</span>.stackArr[i]==<span class=\\"hljs-literal\\">null</span> || <span class=\\"hljs-keyword\\">this</span>.stackArr[i].length&lt;<span class=\\"hljs-keyword\\">this</span>.capacity){\\n        <span class=\\"hljs-keyword\\">this</span>.nextInsertPos=i\\n        <span class=\\"hljs-keyword\\">break</span>\\n      }\\n    }\\n  }\\n\\n\\n};\\n\\n<span class=\\"hljs-comment\\">/**\\n * @return {number}\\n */</span>\\nDinnerPlates.prototype.pop = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\"></span>) </span>{\\n    <span class=\\"hljs-comment\\">// console.log(this.stackArr)</span>\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-keyword\\">this</span>.stackArr.length<span class=\\"hljs-number\\">-1</span>;i&gt;=<span class=\\"hljs-number\\">0</span>;i--){\\n    res=<span class=\\"hljs-keyword\\">this</span>.stackArr[i].pop()\\n    <span class=\\"hljs-keyword\\">this</span>.nextInsertPos=<span class=\\"hljs-built_in\\">Math</span>.min(<span class=\\"hljs-keyword\\">this</span>.nextInsertPos,i)\\n    <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-keyword\\">this</span>.stackArr[i].length===<span class=\\"hljs-number\\">0</span>){\\n      <span class=\\"hljs-keyword\\">this</span>.stackArr.pop()\\n    }\\n    <span class=\\"hljs-keyword\\">break</span>\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * @param {number} index\\n * @return {number}\\n */</span>\\nDinnerPlates.prototype.popAtStack = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">index</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">-1</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-keyword\\">this</span>.stackArr[index].length<span class=\\"hljs-number\\">-1</span>;i&gt;=<span class=\\"hljs-number\\">0</span>;i--){\\n    res=<span class=\\"hljs-keyword\\">this</span>.stackArr[index].pop()\\n    <span class=\\"hljs-keyword\\">this</span>.nextInsertPos=index\\n    <span class=\\"hljs-keyword\\">break</span>\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n\\n<span class=\\"hljs-comment\\">/** \\n * Your DinnerPlates object will be instantiated and called as such:\\n * var obj = new DinnerPlates(capacity)\\n * obj.push(val)\\n * var param_2 = obj.pop()\\n * var param_3 = obj.popAtStack(index)\\n */</span>\\n</code></pre>\\n"],"titleSlug":"dinner-plate-stacks","hasThinking":false,"content":"<p>\u6211\u4eec\u628a\u65e0\u9650\u6570\u91cf &infin; \u7684\u6808\u6392\u6210\u4e00\u884c\uff0c\u6309\u4ece\u5de6\u5230\u53f3\u7684\u6b21\u5e8f\u4ece 0 \u5f00\u59cb\u7f16\u53f7\u3002\u6bcf\u4e2a\u6808\u7684\u7684\u6700\u5927\u5bb9\u91cf&nbsp;<code>capacity</code> \u90fd\u76f8\u540c\u3002</p>\\n\\n<p>\u5b9e\u73b0\u4e00\u4e2a\u53eb\u300c\u9910\u76d8\u300d\u7684\u7c7b&nbsp;<code>DinnerPlates</code>\uff1a</p>\\n\\n<ul>\\n\\t<li><code>DinnerPlates(int capacity)</code>&nbsp;- \u7ed9\u51fa\u6808\u7684\u6700\u5927\u5bb9\u91cf&nbsp;<code>capacity</code>\u3002</li>\\n\\t<li><code>void push(int val)</code>&nbsp;- \u5c06\u7ed9\u51fa\u7684\u6b63\u6574\u6570&nbsp;<code>val</code>&nbsp;\u63a8\u5165&nbsp;<strong>\u4ece\u5de6\u5f80\u53f3\u7b2c\u4e00\u4e2a&nbsp;</strong>\u6ca1\u6709\u6ee1\u7684\u6808\u3002</li>\\n\\t<li><code>int pop()</code>&nbsp;- \u8fd4\u56de&nbsp;<strong>\u4ece\u53f3\u5f80\u5de6\u7b2c\u4e00\u4e2a&nbsp;</strong>\u975e\u7a7a\u6808\u9876\u90e8\u7684\u503c\uff0c\u5e76\u5c06\u5176\u4ece\u6808\u4e2d\u5220\u9664\uff1b\u5982\u679c\u6240\u6709\u7684\u6808\u90fd\u662f\u7a7a\u7684\uff0c\u8bf7\u8fd4\u56de&nbsp;<code>-1</code>\u3002</li>\\n\\t<li><code>int popAtStack(int index)</code>&nbsp;- \u8fd4\u56de\u7f16\u53f7&nbsp;<code>index</code>&nbsp;\u7684\u6808\u9876\u90e8\u7684\u503c\uff0c\u5e76\u5c06\u5176\u4ece\u6808\u4e2d\u5220\u9664\uff1b\u5982\u679c\u7f16\u53f7&nbsp;<code>index</code>&nbsp;\u7684\u6808\u662f\u7a7a\u7684\uff0c\u8bf7\u8fd4\u56de <code>-1</code>\u3002</li>\\n</ul>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a </strong>\\n[&quot;DinnerPlates&quot;,&quot;push&quot;,&quot;push&quot;,&quot;push&quot;,&quot;push&quot;,&quot;push&quot;,&quot;popAtStack&quot;,&quot;push&quot;,&quot;push&quot;,&quot;popAtStack&quot;,&quot;popAtStack&quot;,&quot;pop&quot;,&quot;pop&quot;,&quot;pop&quot;,&quot;pop&quot;,&quot;pop&quot;]\\n[[2],[1],[2],[3],[4],[5],[0],[20],[21],[0],[2],[],[],[],[],[]]\\n<strong>\u8f93\u51fa\uff1a</strong>\\n[null,null,null,null,null,null,2,null,null,20,21,5,4,3,1,-1]\\n\\n<strong>\u89e3\u91ca\uff1a</strong>\\nDinnerPlates D = DinnerPlates(2);  // \u521d\u59cb\u5316\uff0c\u6808\u6700\u5927\u5bb9\u91cf capacity = 2\\nD.push(1);\\nD.push(2);\\nD.push(3);\\nD.push(4);\\nD.push(5);         // \u6808\u7684\u73b0\u72b6\u4e3a\uff1a    2 &nbsp;4\\n&nbsp;                                   1 &nbsp;3 &nbsp;5\\n                                    \ufe48 \ufe48 \ufe48\\nD.popAtStack(0);   // \u8fd4\u56de 2\u3002\u6808\u7684\u73b0\u72b6\u4e3a\uff1a     &nbsp;4\\n            &nbsp;                             1 &nbsp;3 &nbsp;5\\n                                          \ufe48 \ufe48 \ufe48\\nD.push(20);        // \u6808\u7684\u73b0\u72b6\u4e3a\uff1a  20  4\\n&nbsp;                                  1 &nbsp;3 &nbsp;5\\n                                   \ufe48 \ufe48 \ufe48\\nD.push(21);        // \u6808\u7684\u73b0\u72b6\u4e3a\uff1a  20  4 21\\n&nbsp;                                  1 &nbsp;3 &nbsp;5\\n                                   \ufe48 \ufe48 \ufe48\\nD.popAtStack(0);   // \u8fd4\u56de 20\u3002\u6808\u7684\u73b0\u72b6\u4e3a\uff1a       4 21\\n             &nbsp;                              1 &nbsp;3 &nbsp;5\\n                                            \ufe48 \ufe48 \ufe48\\nD.popAtStack(2);   // \u8fd4\u56de 21\u3002\u6808\u7684\u73b0\u72b6\u4e3a\uff1a       4\\n             &nbsp;                              1 &nbsp;3 &nbsp;5\\n                                            \ufe48 \ufe48 \ufe48 \\nD.pop()            // \u8fd4\u56de 5\u3002\u6808\u7684\u73b0\u72b6\u4e3a\uff1a        4\\n             &nbsp;                              1 &nbsp;3 \\n                                            \ufe48 \ufe48  \\nD.pop()            // \u8fd4\u56de 4\u3002\u6808\u7684\u73b0\u72b6\u4e3a\uff1a    1  3 \\n                                           \ufe48 \ufe48   \\nD.pop()            // \u8fd4\u56de 3\u3002\u6808\u7684\u73b0\u72b6\u4e3a\uff1a    1 \\n                                           \ufe48   \\nD.pop()            // \u8fd4\u56de 1\u3002\u73b0\u5728\u6ca1\u6709\u6808\u3002\\nD.pop()            // \u8fd4\u56de -1\u3002\u4ecd\u7136\u6ca1\u6709\u6808\u3002\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= capacity&nbsp;&lt;= 20000</code></li>\\n\\t<li><code>1 &lt;= val&nbsp;&lt;= 20000</code></li>\\n\\t<li><code>0 &lt;= index&nbsp;&lt;= 100000</code></li>\\n\\t<li>\u6700\u591a\u4f1a\u5bf9&nbsp;<code>push</code>\uff0c<code>pop</code>\uff0c\u548c&nbsp;<code>popAtStack</code>&nbsp;\u8fdb\u884c <code>200000</code> \u6b21\u8c03\u7528\u3002</li>\\n</ul>\\n","title":"1172. \u9910\u76d8\u6808","relatedTags":["\u8bbe\u8ba1"],"difficult":"Hard","lang":["javascript"],"uniqueID":"1172"}')}}]);